    expect(() => matchesSearchQuery(undefined, 'test')).not.toThrow();
    // Empty note object
    expect(matchesSearchQuery({}, 'test')).toBe(false);
    // Null query
    // @ts-expect-error testing runtime behaviour with null query
    expect(matchesSearchQuery({ title: 'test' }, null)).toBe(true);
    // Undefined query defaults to empty string -> should match any note
    expect(matchesSearchQuery({ title: 'test' }, undefined)).toBe(true);
